453: // cleanupPanelForSaveWithContext mimics the PanelModel.getSaveModel() behavior
454: // This removes properties that shouldn't be persisted and filters out default values
455: func cleanupPanelForSaveWithContext(panel map[string]interface{}, isNested bool) {
456: 	// Apply auto-migration logic (matches frontend PanelModel constructor)
457: 	// This happens during cleanup phase to match when frontend applies auto-migration
458: 	applyPanelAutoMigration(panel)
459: 
460: 	// Library panel specific cleanup (matches frontend behavior)
461: 	// Frontend only preserves id, title, gridPos, and libraryPanel for library panels
462: 	if libraryPanel, hasLibraryPanel := panel["libraryPanel"]; hasLibraryPanel && libraryPanel != nil {
463: 		// Create a new panel with only the essential properties
464: 		essentialProps := map[string]interface{}{
465: 			"id":           panel["id"],
466: 			"title":        panel["title"],
467: 			"gridPos":      panel["gridPos"],
468: 			"libraryPanel": libraryPanel,
469: 		}
470: 
471: 		// Clear the original panel and copy back only essential properties
472: 		for key := range panel {
473: 			delete(panel, key)
474: 		}
475: 		for key, value := range essentialProps {
476: 			if value != nil {
477: 				panel[key] = value
478: 			}
479: 		}
480: 		return // Skip the rest of the cleanup for library panels
481: 	}
482: 
483: 	// Row panel specific cleanup (matches frontend behavior)
484: 	cleanupRowPanelProperties(panel)
485: 
486: 	// Track which properties were present in the input to preserve them even if they become empty
487: 	originalProperties := make(map[string]bool)
488: 	for key := range panel {
489: 		originalProperties[key] = true
490: 	}
491: 	// Properties that should never be persisted (notPersistedProperties)
492: 	notPersistedProps := map[string]bool{
493: 		"events":                  true,
494: 		"isViewing":               true,
495: 		"isEditing":               true,
496: 		"isInView":                true,
497: 		"hasRefreshed":            true,
498: 		"cachedPluginOptions":     true, // This is the key one causing issues
499: 		"plugin":                  true,
500: 		"queryRunner":             true,
501: 		"replaceVariables":        true,
502: 		"configRev":               true,
503: 		"hasSavedPanelEditChange": true,
504: 		"getDisplayTitle":         true,
505: 		"dataSupport":             true,
506: 		"key":                     true,
507: 		"isNew":                   true,
508: 		"refreshWhenInView":       true,
509: 		"scopedVars":              true, // Frontend removes scopedVars from save model
510: 	}
511: 
512: 	// Default values that should be filtered out if they match (defaults)
513: 	defaults := map[string]interface{}{
514: 		"gridPos": map[string]interface{}{
515: 			"x": float64(0), "y": float64(0), "h": float64(3), "w": float64(6),
516: 		},
517: 		"targets": []interface{}{
518: 			map[string]interface{}{"refId": "A"},
519: 		},
520: 		"cachedPluginOptions": map[string]interface{}{},
521: 		"transparent":         false,
522: 		"options":             map[string]interface{}{},
523: 		"links":               []interface{}{},
524: 		"fieldConfig": map[string]interface{}{
525: 			"defaults":  map[string]interface{}{},
526: 			"overrides": []interface{}{},
527: 		},
528: 		"title": "",
529: 	}
530: 
531: 	// Remove notPersistedProperties
532: 	for prop := range notPersistedProps {
533: 		delete(panel, prop)
534: 	}
535: 
536: 	// Filter out properties that match defaults
537: 	for prop, defaultValue := range defaults {
538: 		if panelValue, exists := panel[prop]; exists {
539: 			if isEqual(panelValue, defaultValue) {
540: 				delete(panel, prop)
541: 			}
542: 		}
543: 	}
544: 
545: 	// Remove empty transformations array unless nested panel had them originally
546: 	if transformations, ok := panel["transformations"].([]interface{}); ok && len(transformations) == 0 {
547: 		if panel["_originallyHadTransformations"] != true || !isNested {
548: 			delete(panel, "transformations")
549: 		}
550: 	}
551: 
552: 	// Remove null values recursively to match frontend's JSON.stringify/parse behavior
553: 	// Pass panel type information to help with threshold handling
554: 	panelType := ""
555: 	if t, ok := panel["type"].(string); ok {
556: 		panelType = t
557: 	}
558: 	removeNullValuesRecursivelyWithContext(panel, panelType)
559: 
560: 	// Filter out properties that match defaults (matches frontend's isEqual logic)
561: 	filterDefaultValues(panel, originalProperties)
562: 
563: 	// Clean up internal markers
564: 	delete(panel, "_originallyHadTransformations")
565: 	delete(panel, "_originallyHadFieldConfigCustom")
566: }
