568: // filterDefaultValues removes properties that match the default values (matches frontend's isEqual logic)
569: func filterDefaultValues(panel map[string]interface{}, originalProperties map[string]bool) {
570: 	// Get panel type for panel-specific defaults
571: 	panelType := ""
572: 	if t, ok := panel["type"].(string); ok {
573: 		panelType = t
574: 	}
575: 
576: 	// PanelModel defaults from frontend
577: 	defaults := map[string]interface{}{
578: 		"gridPos": map[string]interface{}{
579: 			"x": 0, "y": 0, "h": 3, "w": 6,
580: 		},
581: 		"targets": []interface{}{
582: 			map[string]interface{}{"refId": "A"},
583: 		},
584: 		"cachedPluginOptions": map[string]interface{}{},
585: 		"transparent":         false,
586: 		"options":             map[string]interface{}{},
587: 		"links":               []interface{}{},
588: 		"fieldConfig": map[string]interface{}{
589: 			"defaults":  map[string]interface{}{},
590: 			"overrides": []interface{}{},
591: 		},
592: 		"title": "",
593: 	}
594: 
595: 	// Add panel-specific defaults
596: 	if panelType == "table" {
597: 		// Remove legacy table properties (matches frontend getSaveModel filtering)
598: 		// Exception: preserve original properties for old table panels with autoMigrateFrom="table-old"
599: 		legacyTableProps := []string{"pageSize", "scroll", "fontSize", "showHeader", "sort"}
600: 		for _, prop := range legacyTableProps {
601: 			if _, exists := panel[prop]; exists {
602: 				if autoMigrateFrom, hasAutoMigrate := panel["autoMigrateFrom"]; hasAutoMigrate && autoMigrateFrom == "table-old" {
603: 					if !originalProperties[prop] {
604: 						delete(panel, prop)
605: 					}
606: 				} else {
607: 					delete(panel, prop)
608: 				}
609: 			}
610: 		}
611: 	}
612: 
613: 	// Remove properties that match defaults, but preserve properties that were originally present
614: 	for prop, defaultValue := range defaults {
615: 		if panelValue, exists := panel[prop]; exists {
616: 			if isEqual(panelValue, defaultValue) {
617: 				// Special case: fieldConfig - handle preservation of original custom object first
618: 				if prop == "fieldConfig" {
619: 					// Check if we need to preserve the custom object before removing fieldConfig
620: 					if panel["_originallyHadFieldConfigCustom"] == true {
621: 						// Ensure fieldConfig structure exists with custom object
622: 						if fieldConfig, ok := panelValue.(map[string]interface{}); ok {
623: 							if defaults, ok := fieldConfig["defaults"].(map[string]interface{}); ok {
624: 								if _, hasCustom := defaults["custom"]; !hasCustom {
625: 									defaults["custom"] = map[string]interface{}{}
626: 								}
627: 								// Don't remove fieldConfig if we added custom back
628: 								continue
629: 							}
630: 						}
631: 					}
632: 					delete(panel, prop)
633: 				} else {
634: 					// Only remove if it wasn't originally present in the input
635: 					if !originalProperties[prop] {
636: 						delete(panel, prop)
637: 					}
638: 				}
639: 			}
640: 		}
641: 	}
642: 
643: 	// Remove empty targets arrays (frontend removes them in cleanup)
644: 	removeIfDefaultValue(panel, "targets", []interface{}{})
645: 
646: 	// Handle case where fieldConfig was removed but originally had custom object
647: 	if panel["_originallyHadFieldConfigCustom"] == true {
648: 		if _, hasFieldConfig := panel["fieldConfig"]; !hasFieldConfig {
649: 			// Recreate fieldConfig with custom object
650: 			panel["fieldConfig"] = map[string]interface{}{
651: 				"defaults": map[string]interface{}{
652: 					"custom": map[string]interface{}{},
653: 				},
654: 				"overrides": []interface{}{},
655: 			}
656: 		}
657: 	}
658: 
659: 	// Clean up fieldConfig to match frontend behavior
660: 	if fieldConfig, exists := panel["fieldConfig"].(map[string]interface{}); exists {
661: 		// Clean up fieldConfig defaults to match frontend behavior
662: 		if defaults, hasDefaults := fieldConfig["defaults"].(map[string]interface{}); hasDefaults {
663: 			// Remove properties that frontend considers as defaults and omits
664: 			cleanupFieldConfigDefaults(defaults, panel)
665: 
666: 			// Preserve custom object if it was originally present, even if empty
667: 			if panel["_originallyHadFieldConfigCustom"] == true {
668: 				if _, hasCustom := defaults["custom"]; !hasCustom {
669: 					defaults["custom"] = map[string]interface{}{}
670: 				}
671: 			}
672: 		}
673: 	}
674: }
