839: 		// Frontend filters: !(panel.repeatPanelId || panel.repeatedByRow)
840: 		filteredPanels := []interface{}{}
841: 		for _, panelInterface := range panels {
842: 			if panel, ok := panelInterface.(map[string]interface{}); ok {
843: 				// Skip panels with repeatPanelId or repeatedByRow
844: 				if _, hasRepeatPanelId := panel["repeatPanelId"]; hasRepeatPanelId {
845: 					continue
846: 				}
847: 				if _, hasRepeatedByRow := panel["repeatedByRow"]; hasRepeatedByRow {
848: 					continue
849: 				}
850: 				filteredPanels = append(filteredPanels, panel)
851: 			}
852: 		}
853: 
854: 		cleanupPanelList(filteredPanels)
855: 		sortPanelsByGridPosition(filteredPanels)
856: 		dashboard["panels"] = filteredPanels
857: 	} else {
858: 		// Ensure panels property exists even if empty (matches frontend behavior)
859: 		dashboard["panels"] = []interface{}{}
860: 	}
