881: // sortPanelsByGridPosition sorts panels by grid position (matches frontend sortPanelsByGridPos behavior)
882: func sortPanelsByGridPosition(panels []interface{}) {
883: 	sort.SliceStable(panels, func(i, j int) bool {
884: 		panelA, okA := panels[i].(map[string]interface{})
885: 		panelB, okB := panels[j].(map[string]interface{})
886: 		if !okA || !okB {
887: 			return false
888: 		}
889: 
890: 		// Get gridPos or use default values if missing
891: 		gridPosA, okA := panelA["gridPos"].(map[string]interface{})
892: 		gridPosB, okB := panelB["gridPos"].(map[string]interface{})
893: 
894: 		// Default gridPos values (matches frontend PanelModel defaults)
895: 		defaultY := float64(0)
896: 		defaultX := float64(0)
897: 
898: 		yA := defaultY
899: 		if okA {
900: 			if y, ok := gridPosA["y"].(float64); ok {
901: 				yA = y
902: 			} else if y, ok := gridPosA["y"].(int); ok {
903: 				yA = float64(y)
904: 			}
905: 		}
906: 
907: 		yB := defaultY
908: 		if okB {
909: 			if y, ok := gridPosB["y"].(float64); ok {
910: 				yB = y
911: 			} else if y, ok := gridPosB["y"].(int); ok {
912: 				yB = float64(y)
913: 			}
914: 		}
915: 
916: 		if yA == yB {
917: 			xA := defaultX
918: 			if okA {
919: 				if x, ok := gridPosA["x"].(float64); ok {
920: 					xA = x
921: 				} else if x, ok := gridPosA["x"].(int); ok {
922: 					xA = float64(x)
923: 				}
924: 			}
925: 
926: 			xB := defaultX
927: 			if okB {
928: 				if x, ok := gridPosB["x"].(float64); ok {
929: 					xB = x
930: 				} else if x, ok := gridPosB["x"].(int); ok {
931: 					xB = float64(x)
932: 				}
933: 			}
934: 			return xA < xB
935: 		}
936: 		return yA < yB
937: 	})
938: }
