951: // applyPanelAutoMigration applies the same auto-migration logic as the frontend PanelModel constructor
952: func applyPanelAutoMigration(panel map[string]interface{}) {
953: 	panelType, ok := panel["type"].(string)
954: 	if !ok {
955: 		return
