1032: // cleanupFieldConfigDefaults removes properties that frontend considers as defaults and omits
1033: func cleanupFieldConfigDefaults(defaults map[string]interface{}, panel map[string]interface{}) {
1034: 	// Don't remove mappings, color objects, or unit properties - frontend preserves them
1035: 
1036: 	// Remove empty custom objects from migrated singlestat panels (frontend filters them out)
1037: 	if custom, exists := defaults["custom"].(map[string]interface{}); exists {
1038: 		if len(custom) == 0 {
1039: 			// Check if this is a migrated singlestat panel by looking for characteristic properties
1040: 			isMigratedSinglestat := false
1041: 
1042: 			// Check for autoMigrateFrom property first
1043: 			if autoMigrateFrom, exists := panel["autoMigrateFrom"]; exists {
1044: 				if autoMigrateFrom == "singlestat" || autoMigrateFrom == "grafana-singlestat-panel" {
1045: 					isMigratedSinglestat = true
1046: 				}
1047: 			}
1048: 
1049: 			// If autoMigrateFrom is not present, check for characteristic migrated singlestat properties
1050: 			if !isMigratedSinglestat {
1051: 				// Check for color with fixedColor and mode "fixed" (from sparkline migration)
1052: 				if color, hasColor := defaults["color"].(map[string]interface{}); hasColor {
1053: 					if _, hasFixedColor := color["fixedColor"].(string); hasFixedColor {
1054: 						if mode, hasMode := color["mode"].(string); hasMode && mode == "fixed" {
1055: 							// Check for mappings array (from valueMaps migration)
1056: 							if _, hasMappings := defaults["mappings"].([]interface{}); hasMappings {
1057: 								isMigratedSinglestat = true
1058: 							}
1059: 						}
1060: 					}
1061: 				}
1062: 			}
1063: 
1064: 			// Only remove empty custom objects for migrated singlestat panels
1065: 			if isMigratedSinglestat {
1066: 				delete(defaults, "custom")
1067: 			}
1068: 		}
1069: 	}
1070: }
