1084: // trackPanelOriginalTransformations recursively tracks transformations in panels and nested panels
1085: func trackPanelOriginalTransformations(panel map[string]interface{}) {
1086: 	// Mark if this panel had transformations in original input
1087: 	if _, hasTransformations := panel["transformations"]; hasTransformations {
1088: 		panel["_originallyHadTransformations"] = true
1089: 	}
