   182→// migrateTableDisplayModeToCellOptions converts the old displayMode string to the new cellOptions format
   183→func migrateTableDisplayModeToCellOptions(displayMode string) map[string]interface{} {
   184→	switch displayMode {
   185→	case "basic", "gradient-gauge", "lcd-gauge":
   186→		gaugeMode := "basic"
   187→		switch displayMode {
   188→		case "gradient-gauge":
   189→			gaugeMode = "gradient"
   190→		case "lcd-gauge":
   191→			gaugeMode = "lcd"
   192→		}
   193→		return map[string]interface{}{
   194→			"type": "gauge",
   195→			"mode": gaugeMode,
   196→		}
   197→
   198→	case "color-background", "color-background-solid":
   199→		mode := "basic"
   200→		if displayMode == "color-background" {
   201→			mode = "gradient"
   202→		}
   203→		return map[string]interface{}{
   204→			"type": "color-background",
   205→			"mode": mode,
   206→		}
   207→
   208→	default:
   209→		return map[string]interface{}{
   210→			"type": displayMode,
   211→		}
   212→	}
   213→}
